+        ) {
+            let alignment = 1_usize << alignment_shift;
+            let aligned = AlignedVec::new(size, alignment);
+            prop_assert_eq!(aligned.len(), size);
+            if size > 0 {
+                let ptr = aligned.as_slice().as_ptr() as usize;
+                prop_assert_eq!(
